// Package ecc implements a generic interface for ECDH, ECDSA, and EdDSA.package eccimport ("io""math/big")type Curve interface {GetCurveName() string}type ECDSACurve interface {CurveMarshalIntegerPoint(x, y *big.Int) []byteUnmarshalIntegerPoint([]byte) (x, y *big.Int)MarshalIntegerSecret(d *big.Int) []byteUnmarshalIntegerSecret(d []byte) *big.IntGenerateECDSA(rand io.Reader) (x, y, secret *big.Int, err error)Sign(rand io.Reader, x, y, d *big.Int, hash []byte) (r, s *big.Int, err error)Verify(x, y *big.Int, hash []byte, r, s *big.Int) boolValidateECDSA(x, y *big.Int, secret []byte) error}type EdDSACurve interface {CurveMarshalBytePoint(x []byte) []byteUnmarshalBytePoint([]byte) (x []byte)MarshalByteSecret(d []byte) []byteUnmarshalByteSecret(d []byte) []byteMarshalSignature(sig []byte) (r, s []byte)UnmarshalSignature(r, s []byte) (sig []byte)GenerateEdDSA(rand io.Reader) (pub, priv []byte, err error)Sign(publicKey, privateKey, message []byte) (sig []byte, err error)Verify(publicKey, message, sig []byte) boolValidateEdDSA(publicKey, privateKey []byte) (err error)}type ECDHCurve interface {CurveMarshalBytePoint([]byte) (encoded []byte)UnmarshalBytePoint(encoded []byte) []byteMarshalByteSecret(d []byte) []byteUnmarshalByteSecret(d []byte) []byteGenerateECDH(rand io.Reader) (point []byte, secret []byte, err error)Encaps(rand io.Reader, point []byte) (ephemeral, sharedSecret []byte, err error)Decaps(ephemeral, secret []byte) (sharedSecret []byte, err error)ValidateECDH(public []byte, secret []byte) error}